fprintf('Number of Equality Constraints: %d\n', num_eq_constraints); %[output:6d0dcdbb]
fprintf('Number of Inequality Constraints: %d\n', num_ineq_constraints); %[output:709fde84]
fprintf('Number of Bound Constraints: %d\n', num_bound_constraints); %[output:75f818e6]
fprintf('Number of Objective Variables: %d\n', num_obj_vars); %[output:441cd314]
