exportgraphics(gcf, fullfile(graphicFolder, 'clinical_interest_tradeoff.pdf'), 'Resolution', 600); %[output:15f5af54]
exportgraphics(gcf, fullfile(graphicFolder, 'clinical_interest_tradeoff.png'), 'Resolution', 600); %[output:15f5af54]
%%
%[text] ## Model Comparison
clear problem
% ========== Configuration ==========
max_hospitals = 24;
[m, n] = size(D);  % D = prevalence matrix, already defined in workspace
total_patients_heuristic = zeros(max_hospitals, 1);
total_patients_optimised = zeros(max_hospitals, 1);

% ========== Loop Over Number of HCPs ==========
for k = 1:max_hospitals
    selected_HCPs = 1:k;  % Select first k hospitals
    D_k = D(:, selected_HCPs);  % Subset prevalence
    n_k = length(selected_HCPs);  % Update size
    HCPcap_k = HCPpatientNumberUB(selected_HCPs);

    %% === HEURISTIC PATIENT RECRUITMENT ===
    [Yh, ~, total_patients_heuristic(k)] = HeuristicPatientRecruitment(D_k, patientNumberUB, HCPcap_k);

    %% === GLOBAL GREEDY MARGINAL PATIENT RECRUITMENT ===
    optsR = struct('useScarcity', true, 'tieBreak', 'minIndex');
    [Yg, ~, total_patients_greedy(k)] = GlobalGreedyMarginalPatientRecruitment(D_k, patientNumberUB, HCPcap_k, optsR);

    %% === CARDINALITY OPTIMISED ALLOCATION ===
    % Build commutation matrix
    [I, J] = ndgrid(1:m, 1:n_k);
    p_idx = n_k * (I(:) - 1) + J(:);
    q_idx = m * (J(:) - 1) + I(:);
    Kmn = sparse(p_idx, q_idx, 1, m*n_k, m*n_k);

    % Matrices for constraints
    P_y = kron(ones(n_k, 1)', eye(m));
    P_z = kron(ones(m, 1)', eye(n_k)) * Kmn;

    LHS = [diag(D_k(:))     ,    -speye(m*n_k)     ,        zeros(m*n_k, m) ,        zeros(m*n_k, n_k); ...
           zeros(m, m*n_k)  ,    P_y               ,        -speye(m)       ,        zeros(m, n_k)    ; ...
           zeros(n_k, m*n_k),    P_z               ,        zeros(n_k, m)   ,        -speye(n_k)      ];

    % Problem setup
    variableSize = (m*n_k)*2 + m + n_k;
    lb = sparse(variableSize, 1);
    ub = 1e4 * ones(variableSize, 1);

    maxFeasiblePatients = sum(D_k, 2);
    lb(1:m*n_k) = 0;  ub(1:m*n_k) = 1;  % X variable
    lb(m*n_k+1:2*m*n_k) = 0;           % Y variableIMDLb .* (maxPatientsPerIMD >= IMDLb)
    lb(2*m*n_k+1:2*m*n_k+m) = 0;
    ub(2*m*n_k+1:2*m*n_k+m) = patientNumberUB;
    ub(2*m*n_k+m+1:end) = HCPcap_k(:);

    csense = repmat('E', m*n_k + m + n_k, 1);

    problem.p = false(variableSize, 1); problem.p(1:m*n_k) = true;
    problem.q = false(variableSize, 1); problem.q(2*m*n_k+1:2*m*n_k+m) = true;
    problem.r = ~(problem.p | problem.q);

    problem.A = LHS;
    problem.b = zeros(size(LHS,1), 1);
    problem.c = zeros(variableSize, 1);
    problem.csense = csense;
    problem.lb = lb;
    problem.ub = ub;

    % Objective
    problem.lambda0 = 1;
    problem.lambda1 = 0;
    problem.delta0  = 0;
    problem.delta1  = -1;
    problem.alpha1  = 0;

    % Solve
    param.printLevel = 0;
    solution = optimizeCardinality(problem, param);

    if isempty(solution.xyz)
        warning('Optimisation failed at HCP = %d', k);
        total_patients_optimised(k) = NaN;
    else
        y_opt = solution.xyz(2*m*n_k+1:2*m*n_k+m);
        total_patients_optimised(k) = sum(y_opt);
    end
end

%%

%% ========== Plotting ==========
figure('Units', 'inches', 'Position', [1, 1, 6, 5]);  % Figure size suitable for publication %[output:06ab224c]
x = (1:max_hospitals).';               % Ensure x is a column vector
th = total_patients_heuristic(:);      % Ensure data are column vectors
opt = total_patients_optimised(:);
gr = total_patients_greedy(:);

% Create polygon coordinates for the filled area
x_fill = [x; flipud(x)];
y_fill = [gr; flipud(opt)];

% Plot the filled area first (it will be at the back)
fill(x_fill, y_fill, [0, 1, 0], 'FaceAlpha', 0.2, 'EdgeColor', 'none'); hold on; %[output:06ab224c]

% Plot the lines on top
plot(x, th, '-o', 'LineWidth', 1.5); %[output:06ab224c]
plot(x, gr, '-^', 'LineWidth', 1.5); %[output:06ab224c]
plot(x, opt, '-s', 'LineWidth', 1.5); %[output:06ab224c]

set(gca, 'FontName', 'Arial', 'FontSize', 12); %[output:06ab224c]
xlabel('Number of Engaged Hospitals (HCPs)'); %[output:06ab224c]
ylabel('Total Patients Recruited'); %[output:06ab224c]
xlim([0, 24]) %[output:06ab224c]

% title('Optimisation Gain vs Heuristic (HCP Engagement)', 'Units', 'normalized', 'FontWeight', 'normal');

legend('Optimisation Gain', 'Heuristic', 'Global Greedy', 'Cardinality-Optimised Model', ... %[output:06ab224c]
       'Location', 'northwest'); %[output:06ab224c]
grid off; %[output:06ab224c]

% Save as high-resolution EPS
set(gcf, 'PaperPositionMode', 'auto');
exportgraphics(gcf, fullfile(graphicFolder, 'optimisation_vs_heuristic.eps'), 'Resolution', 600); %[output:06ab224c]
%%
%[text] ## Compare metabolomic cost for optimisation and Heuristic model
% Generate all combinations of row indices i and column indices j
[I, J] = ndgrid(1:m, 1:n);

% Compute the position indices in vec(A') and vec(A)
p_idx = n * (I(:) - 1) + J(:);  % Indices in vec(A')
q_idx = m * (J(:) - 1) + I(:);  % Indices in vec(A)

% Create the sparse commutation matrix
Kmn = sparse(p_idx, q_idx, ones(m * n, 1), m * n, m * n);

[p, q] = size(T);

% Generate a random number for number of global platforms
[p, w] = size(G);

clear problem 

% Defining left hand-side matrix
%   vec(X)  (m*n)               vec(Y)  (m*n)                y  (m*1)               z   (n*1)              vec(U)   (q*m)              vec(H)  (w*m)                     u (q*1)                        h (w*1)                  vec(S)  (m*p)               vec(beta)   (m*1)              vec(gamma)   (m*1)
LHS = [diag(D(:))   ,           -speye(m*n)     ,            sparse(m*n, m)     ,   sparse(m*n, n)    ,    sparse(m*n, m*q) ,          sparse(m*n, m*w) ,                sparse(m*n, q),                sparse(m*n, w),          sparse(m*n, m*p),           sparse(m*n, m),                sparse(m*n, m);...
    sparse(m, m*n)  ,           P_y             ,            -speye(m)          ,   sparse(m, n)      ,    sparse(m, m*q)   ,          sparse(m, m*w)   ,                sparse(m, q)  ,                sparse(m, w)  ,          sparse(m, m*p)  ,           sparse(m, m)  ,                sparse(m, m)  ;...
    sparse(n, m*n)  ,           P_z             ,            sparse(n, m)       ,   -speye(n)         ,    sparse(n, m*q)   ,          sparse(n, m*w)   ,                sparse(n, q)  ,                sparse(n, w)  ,          sparse(n, m*p)  ,           sparse(n, m)  ,                sparse(n, m)  ;...
    sparse(m*p, m*n),           sparse(m*p, m*n),            sparse(m*p, m)     ,   sparse(m*p, n)    ,    kron(speye(m), T),          sparse(m*p, m*w) ,                sparse(m*p, q),                sparse(m*p, w),          -2*speye(m*p)   ,           sparse(m*p, m),                sparse(m*p, m);...
    sparse(m*p, m*n),           sparse(m*p, m*n),            sparse(m*p, m)     ,   sparse(m*p, n)    ,    sparse(m*p, m*q) ,          kron(speye(m), G),                sparse(m*p, q),                sparse(m*p, w),          -2*speye(m*p)   ,           sparse(m*p, m),                sparse(m*p, m);...
    sparse(m*p, m*n),           sparse(m*p, m*n),            kron(speye(m), B)*L,   sparse(m*p, n)    ,    sparse(m*p, m*q) ,          sparse(m*p, m*w) ,                sparse(m*p, q),                sparse(m*p, w),          -speye(m*p)     ,           sparse(m*p, m),                sparse(m*p, m);...
    sparse(q, m*n)  ,           sparse(q, m*n)  ,            sparse(q, m)       ,   sparse(q, n)      ,    P_u              ,          sparse(q, m*w)   ,                -speye(q)     ,                sparse(q, w)  ,          sparse(q, m*p)  ,           sparse(q, m)  ,                sparse(q, m)  ;...
    sparse(w, m*n)  ,           sparse(w, m*n)  ,            sparse(w, m)       ,   sparse(w, n)      ,    sparse(w, m*q)   ,          P_h              ,                sparse(w, q)  ,                -speye(w)     ,          sparse(w, m*p)  ,           sparse(w, m)  ,                sparse(w, m)  ;...    
    sparse(m, m*n)  ,           sparse(m, m*n)  ,            sparse(m, m)       ,   sparse(m, n)      ,    kron(speye(m), r),          sparse(m, m*w)   ,                sparse(m, q)  ,                sparse(m, w)  ,          sparse(m, m*p)  ,           -speye(m, m)  ,                sparse(m, m)  ;...
    sparse(m, m*n)  ,           sparse(m, m*n)  ,            sparse(m, m)       ,   sparse(m, n)      ,     sparse(m, m*q)  ,          kron(speye(m), a),                sparse(m, q)  ,                sparse(m, w)  ,          sparse(m, m*p)  ,           sparse(m, m)  ,                -speye(m, m)  ];


% Define Optimise Cardinality problem:
% Define p, vector for zero-norm cardinality
variableSize = (m*n) + (m*n) + m + n + (m*q) + (m*w) + (q*1) + (w*1) + (m*p) + (m*1) + (m*1);
problem.p = false(variableSize, 1);
% ||vec(X)||_0
problem.p(1:(m*n)) = true;

% ||vec(U)||_0
problem.p((m*n) + (m*n) + m + n +1:(m*n) + (m*n) + m + n + (m*q)) = true;

% ||vec(H)||_0
problem.p((m*n) + (m*n) + m + n + (m*q) + 1:(m*n) + (m*n) + m + n + (m*q) + (m*w)) = true;

% Define q vector for one-norm cardinality
problem.q = false(variableSize, 1);

% ||(y)||_1
problem.q(2*m*n+1: 2*m*n+m+1) = true;

% ||beta||_1 + ||gamma||_1
problem.q(2*m*n + m + n + q*m + w*m + q + w + m*p + 1 : end) = true;

% Global parameter on one-norm minimisation
% `min c'(x, y, z) + lambda_0*k.||*x||_0 + lambda_1*o.*||x||_1
%                  -  delta_0*d.||*y||_0 +  delta_1*o.*||y||_1` 
%                                        +  alpha_1*o.*||z||_1`
problem.lambda0 = 1;
problem.lambda1 = 0;
problem.delta0  = 0;
problem.delta1  = 1;
problem.alpha1  = 0;
% Therefore the problem is converted to:
% `min c'(x, y, z) + k.||*x||_0 +  o.*||y||_1` 

% Define rho coefficient to scale total cost objectives. rho = 0.01
problem.o = zeros(variableSize,1);
problem.o(2*m*n + m + n + q*m + w*m + q + w + m*p + 1 : end) = 0.01;

% Define r
problem.r = ~(problem.p + problem.q);

% Define bounds
lb = zeros(variableSize, 1);
% Relax the upper bound
ub = 10000 + zeros(variableSize, 1);

% set the lower bounds for X variable
lb(1:(m*n)) = 0;
ub(1:(m*n)) = 1;

% Set number of patients per IMD to the half possible value y
% if       lb_y <  y  <  ub_y
% Then    -lb_y > -y  > -ub_y
% Assume minimum 15 patients per IMD
% Set number of patients to numbers calculated by Diagnostic Confidence Score
% lb(m*n+m*n+1: m*n+m*n+m) = -patientNumberUB;
% ub(m*n+m*n+1: m*n+m*n+m) = -0.5 * patientNumberLB;
lb(m*n+m*n+1: m*n+m*n+m) = ceil(0.50 * patientNumberLB);
ub(m*n+m*n+1: m*n+m*n+m) = patientNumberUB;
% Minimum 50 patients to be recruited at each hospital
ub(m*n+m*n+m+1: m*n+m*n+m+n) = HCPpatientNumberUB;

% Set a cap on samples per site u
ub((m*n) + (m*n) + m + n + (m*q) + (m*w) + 1: (m*n) + (m*n) + m + n + (m*q) + (m*w) + q) = repmat(2000, q, 1);

% Set a cap on samples per site h
ub((m*n) + (m*n) + m + n + (m*q) + (m*w) + (q*1) + 1: (m*n) + (m*n) + m + n + (m*q) + (m*w) + (q*1) + (w*1)) = repmat(2000, w, 1);

% Define csense
csense = [repmat('E', m*n+m+n, 1); repmat('G', 2*m*p, 1); repmat('E', q + w + m*p + 2*m, 1)];
problem.p = logical(problem.p);
problem.q = logical(problem.q);
problem.r = logical(problem.r);
problem.A = LHS;
problem.b = zeros(size(problem.A, 1), 1);
problem.ub = ub;
problem.lb = lb;
problem.c = zeros(size(problem.A,2),1);
problem.csense = csense;
param.printLevel=1;


solution = optimizeCardinality(problem, param); %[output:2e24213f]
% Test the results
assert(~isempty(solution.xyz), 'Empty solution')

% Reshape the vectorised variables
% X
X_opt = solution.xyz(1:m*n);
X_opt = reshape(X_opt, m, n);

% Y
Y_opt = solution.xyz(m*n+1: 2*m*n);
Y_opt = reshape(Y_opt, m, n);

% y
y_opt = solution.xyz(2*m*n+1:2*m*n+m);
y_opt = reshape(y_opt, m, 1);

% z
z_opt = solution.xyz(2*m*n+m+1:2*m*n+m+n);
z_opt = reshape(z_opt, n, 1);

% U
U_opt = solution.xyz(2*m*n+m+n+1: 2*m*n+m+n+m*q);
U_opt = reshape(U_opt, q, m);

% H
H_opt = solution.xyz(2*m*n+m+n+m*q+1: 2*m*n+m+n+m*q+m*w);
H_opt = reshape(H_opt, w, m);

% S
S_opt = solution.xyz(2*m*n+m+n+m*q+m*w+1: 2*m*n+m+n+m*q+m*w+m*p);
S_opt = reshape(S_opt, p, m);

% Beta
beta_opt = solution.xyz(2*m*n+m+n+m*q+m*w+q+w+m*p+1: 2*m*n+m+n+m*q+m*w+q+w+m*p+m);
beta_opt = reshape(beta_opt, 1, m);

% Gamma
gamma_opt = solution.xyz(2*m*n+m+n+m*q+m*w+q+w+m*p+m+1: 2*m*n+m+n+m*q+m*w+q+w+m*p+m + m);
gamma_opt = reshape(gamma_opt, 1, m);


% Step 1: Recalculate total costs for Model B
targSamples_opt = sum(U_opt, 2);   % q×1
globSamples_opt = sum(H_opt, 2);   % w×1
costT_opt = sum(targSamples_opt .* r(:));
costG_opt = sum(globSamples_opt .* a(:));
totalCost_opt = costT_opt + costG_opt;

% ---------------- Heuristic baseline (as you currently have it) ----------------
[U_heur, H_heur, costT_heur, costG_heur, totalCost_heur] = ...
    HeuristicSampleAllocation(y, T, G, r, a, B);

S = B * diag(y);   % p×m (single coverage)
assert(all(all(T * U_heur >= S)), 'Targeted coverage assertion failed (heuristic)');
assert(all(all(G * H_heur >= S)), 'Global coverage assertion failed (heuristic)');

% ---------------- Global Greedy baseline (enhanced) ----------------
optsGreedy = struct();
optsGreedy.batchMode = false;          % 1 sample at a time (stronger under caps)
optsGreedy.activationPenaltyT = 0;     % keep 0 for now
optsGreedy.activationPenaltyG = 0;
optsGreedy.useTwoXCoverage = true;     % match optimisation convention

capT = 2000 * ones(q,1);
capG = 2000 * ones(w,1);

[U_greedy, H_greedy, costT_greedy, costG_greedy, totalCost_greedy, statsGreedy] = ...
    GlobalGreedyMarginalSampleAllocation(y, T, G, r, a, B, capT, capG, optsGreedy);

S2 = 2 * (B * diag(y));   % p×m (double coverage)
assert(all(all(T * U_greedy >= S2)), 'Targeted coverage assertion failed (greedy, 2x)');
assert(all(all(G * H_greedy >= S2)), 'Global coverage assertion failed (greedy, 2x)');


% Check to make sure all the results are digits
assert( all(Y_opt(:) == round(Y_opt(:))), 'Matrix Y must contain only integer values.');
assert( all(H_opt(:) == round(H_opt(:))), 'Matrix H must contain only integer values.');
assert( all(U_opt(:) == round(U_opt(:))), 'Matrix U must contain only integer values.');
%%
%[text] ## Plot the results
%% === Plot the results: Heuristic vs Global Greedy vs Optimised (k€) ===
labels = {'Targeted Cost','Global Cost','Total Cost'};

heuristic_costs = [costT_heur,   costG_heur,   totalCost_heur];
greedy_costs    = [costT_greedy, costG_greedy, totalCost_greedy];
optimised_costs = [costT_opt,    costG_opt,    totalCost_opt];

% Convert to thousand euros
scale = 1e3;
heuristic_k = heuristic_costs / scale;
greedy_k    = greedy_costs    / scale;
optimised_k = optimised_costs / scale;

x = 1:numel(labels);
bar_width = 0.75;

figure('Units','inches','Position',[1,1,6.5,4]); %[output:0a649965]
hold on; %[output:0a649965]

cost_k = [heuristic_k; greedy_k; optimised_k];   % 3-by-3 (in k€)
b = bar(x, cost_k', bar_width); %[output:0a649965]

% Colors
b(1).FaceColor = [0.30 0.55 0.85];   % Blue  – Heuristic %[output:0a649965]
b(2).FaceColor = [0.90 0.60 0.00];   % Amber – Global Greedy %[output:0a649965]
b(3).FaceColor = [0.00 0.60 0.50];   % Teal  – Optimised %[output:0a649965]

ylabel('Cost (thousand euros)');  % <-- scaled axis %[output:0a649965]
set(gca, 'XTick', x, 'XTickLabel', labels); %[output:0a649965]

legend('Heuristic', 'Global Greedy', 'Recruitment and Allocation Model', ... %[output:0a649965]
       'Location', 'northwest'); %[output:0a649965]

ylim([0, max(cost_k(:)) * 1.15]); %[output:0a649965]
set(gca, 'FontName', 'Arial', 'FontSize', 10); %[output:0a649965]
% 
% title(sprintf('Metabolomic Analysis Cost Comparison for %d Patients', round(sum(y_opt))), ...
%       'FontSize', 10, 'Units', 'normalized', 'Position', [0.5,1.05,0], ...
%       'FontWeight', 'normal');
grid off; %[output:0a649965]

% Add value labels above bars (in k€)
yoff = max(cost_k(:)) * 0.02;
for i = 1:3
    x_endpoints = b(i).XEndPoints;
    y_endpoints = b(i).YEndPoints;
    values = cost_k(i, :);
    for j = 1:numel(x_endpoints)
        % show with 1 decimal place to avoid crowding (e.g., 581.8)
        text(x_endpoints(j), y_endpoints(j) + yoff, sprintf('%.1f', values(j)), ... %[output:0a649965]
            'HorizontalAlignment', 'center', 'VerticalAlignment', 'bottom', 'FontSize', 10); %[output:0a649965]
    end
end
fprintf('%s%d', 'Total number of recruited patients: ', round(sum(y_opt))); %[output:8999b025]

set(gcf, 'PaperPositionMode', 'auto');
exportgraphics(gcf, fullfile(graphicFolder, 'metabolomic_cost_opt_vs_heu_vs_greedy.png'), 'Resolution', 600); %[output:0a649965]
exportgraphics(gcf, fullfile(graphicFolder, 'metabolomic_cost_opt_vs_heu_vs_greedy.eps'), "ContentType","vector"); %[output:0a649965]
%%
%[text]{"align":"center"} $%% Optimization Problem\n\n% Objective:\n\\\[\n\\text{min} \\quad \n\\left\\| X \\right\\|\_0 \n- \\| y\\|\_1\n+ \\left\\| U \\right\\|\_0 \n+ \\left\\| H \\right\\|\_0 \n+ \\rho(\\| \\beta \\|\_1 \n+ \\| \\gamma \\|\_1)\n+ \\| W \\|\_1 \n+ \\| F \\|\_1 \n\\\]\n$
%[text]{"align":"center"} $% Subject to:\n\\text{s.t:}\n\\\[\n\\text{diag(vec}(\\mathbf{D})) \\cdot \\text{vec}(X) = \\text{vec}(Y),\n\\\]\n\\\[\n(\\mathbf{{1}\_{n}^{\\mathrm{T}} \\otimes I\_{m}}) \\cdot \\mathrm{vec}(Y) = y\n\\\]\n\\\[\n(\\mathbf{{1}\_{m}^{\\mathrm{T}} \\otimes I\_{n}}) \\cdot \\mathbf{K\_{mn}} \\cdot \\mathrm{vec}(Y) = z\n\\\]\n\\\[\n(\\mathbf{I}\_m \\otimes \\mathbf{T}) \\cdot \\text{vec}(U) \\geq 2\\text{vec}(S),\n\\\]\n\\\[\n(\\mathbf{I}\_m \\otimes \\mathbf{G}) \\cdot \\text{vec}(H) \\geq 2\\text{vec}(S),\n\\\]\n\\\[\n(\\mathbf{I}\_m \\otimes \\mathbf{B}) \\cdot \\mathbf{L} \\cdot y = \\text{vec}(S),\n\\\]\n\\\[\n(\\mathbf{{1}\_{m}^{\\mathrm{T}} \\otimes I\_{q}}) \\cdot \\mathrm{vec}(U) = u\n\\\]\n\\\[\n(\\mathbf{{1}\_{m}^{\\mathrm{T}} \\otimes I\_{w}}) \\cdot \\mathrm{vec}(H) = h\n\\\]\n\\\[\n(\\mathbf{I}\_m \\otimes \\mathbf{r}) \\cdot \\text{vec}(U) = \\text{vec}(\\beta),\n\\\]\n\\\[\n(\\mathbf{I}\_m \\otimes \\mathbf{a}) \\cdot \\text{vec}(H) = \\text{vec}(\\gamma),\n\\\]\n\\\[\n\\mathbf{\\mathbf{A\_{\\mathit{(m.t)\\times(m.n)}}}}\\cdotp\\mathrm{vec}(Y)-\\mathbf{\\mathbf{A\_{\\mathit{(m.t)\\times(m.q)}}}}\\cdotp\\mathbf{K}\_{qm}\\cdotp\\mathrm{vec}(U) \\leq \\text{vec}(F),\n\\\]\n\\\[\n-\\mathbf{\\mathbf{A\_{\\mathit{(m.t)\\times(m.n)}}}}\\cdotp\\mathrm{vec}(Y)+\\mathbf{\\mathbf{A\_{\\mathit{(m.t)\\times(m.q)}}}}\\cdotp\\mathbf{K}\_{qm}\\cdotp\\mathrm{vec}(U) \\leq \\text{vec}(F),\n\\\]\n\\\[\n\\mathbf{\\mathbf{A\_{\\mathit{(m.g)\\times(m.n)}}}}\\cdotp\\mathrm{vec}(Y)-\\mathbf{\\mathbf{A\_{\\mathit{(m.g)\\times(m.w)}}}}\\cdotp\\mathbf{K}\_{wm}\\cdotp\\mathrm{vec}(H) \\leq \\text{vec}(W),\n\\\]\n\\\[\n-\\mathbf{\\mathbf{A\_{\\mathit{(m.g)\\times(m.n)}}}}\\cdotp\\mathrm{vec}(Y)+\\mathbf{\\mathbf{A\_{\\mathit{(m.g)\\times(m.w)}}}}\\cdotp\\mathbf{K}\_{wm}\\cdotp\\mathrm{vec}(H) \\leq \\text{vec}(W),\n\\\]\n\\\[\n0 \\leq X \\leq 1,\n\\\]\n\\\[\nlb\_y \\leq y \\leq ub\_y,\n\\\]\n\\\[\nlb\_z \\leq z \\leq ub\_z,\n\\\]\n\\\[\nlb\_u \\leq u \\leq ub\_u,\n\\\]\n\\\[\nlb\_h \\leq h \\leq ub\_h.\n\\$
%[text] ## Compare metabolomic cost for Model B and Heuristic model
% Generate all combinations of row indices i and column indices j
[I, J] = ndgrid(1:m, 1:n);

% Compute the position indices in vec(A') and vec(A)
p_idx = n * (I(:) - 1) + J(:);  % Indices in vec(A')
q_idx = m * (J(:) - 1) + I(:);  % Indices in vec(A)

% Create the sparse commutation matrix
Kmn = sparse(p_idx, q_idx, ones(m * n, 1), m * n, m * n);

[p, q] = size(T);
[~, w] = size(G);

% Define a cap for analysis capacity for each omics site
P_u = kron(ones(m, 1)', eye(q));
P_h = kron(ones(m, 1)', eye(w));

% Check the variables
assert(all(P_u*round(U_opt(:)) == sum(round(U_opt),2)))
assert(all(P_h*round(H_opt(:)) == sum(round(H_opt),2)))


clear problem 

% Defining left hand-side matrix
%   vec(X)  (m*n)               vec(Y)  (m*n)                y  (m*1)               z   (n*1)              vec(U)   (q*m)              vec(H)  (w*m)                     u (q*1)                        h (w*1)                    vec(S)  (m*p)               vec(beta)   (m*1)              vec(gamma)   (m*1)
LHS = [diag(D(:))   ,           -speye(m*n)     ,            sparse(m*n, m)     ,   sparse(m*n, n)    ,    sparse(m*n, m*q) ,          sparse(m*n, m*w) ,                sparse(m*n, q),                sparse(m*n, w),            sparse(m*n, m*p),           sparse(m*n, m),                sparse(m*n, m);...
    sparse(m, m*n)  ,           P_y             ,            -speye(m)          ,   sparse(m, n)      ,    sparse(m, m*q)   ,          sparse(m, m*w)   ,                sparse(m, q)  ,                sparse(m, w)  ,            sparse(m, m*p)  ,           sparse(m, m)  ,                sparse(m, m)  ;...
    sparse(n, m*n)  ,           P_z             ,            sparse(n, m)       ,   -speye(n)         ,    sparse(n, m*q)   ,          sparse(n, m*w)   ,                sparse(n, q)  ,                sparse(n, w)  ,            sparse(n, m*p)  ,           sparse(n, m)  ,                sparse(n, m)  ;...
    sparse(m*p, m*n),           sparse(m*p, m*n),            sparse(m*p, m)     ,   sparse(m*p, n)    ,    kron(speye(m), T),          sparse(m*p, m*w) ,                sparse(m*p, q),                sparse(m*p, w),            -2*speye(m*p)   ,           sparse(m*p, m),                sparse(m*p, m);...
    sparse(m*p, m*n),           sparse(m*p, m*n),            sparse(m*p, m)     ,   sparse(m*p, n)    ,    sparse(m*p, m*q) ,          kron(speye(m), G),                sparse(m*p, q),                sparse(m*p, w),            -2*speye(m*p)   ,           sparse(m*p, m),                sparse(m*p, m);...
    sparse(m*p, m*n),           sparse(m*p, m*n),            kron(speye(m), B)*L,   sparse(m*p, n)    ,    sparse(m*p, m*q) ,          sparse(m*p, m*w) ,                sparse(m*p, q),                sparse(m*p, w),            -speye(m*p)     ,           sparse(m*p, m),                sparse(m*p, m);...
    sparse(q, m*n)  ,           sparse(q, m*n)  ,            sparse(q, m)       ,   sparse(q, n)      ,    P_u              ,          sparse(q, m*w)   ,                -speye(q)     ,                sparse(q, w)  ,            sparse(q, m*p)  ,           sparse(q, m)  ,                sparse(q, m)  ;...
    sparse(w, m*n)  ,           sparse(w, m*n)  ,            sparse(w, m)       ,   sparse(w, n)      ,    sparse(w, m*q)   ,          P_h              ,                sparse(w, q)  ,                -speye(w)     ,            sparse(w, m*p)  ,           sparse(w, m)  ,                sparse(w, m)  ;...    
    sparse(m, m*n)  ,           sparse(m, m*n)  ,            sparse(m, m)       ,   sparse(m, n)      ,    kron(speye(m), r),          sparse(m, m*w)   ,                sparse(m, q)  ,                sparse(m, w)               sparse(m, m*p)  ,           -speye(m, m)  ,                sparse(m, m)  ;...
    sparse(m, m*n)  ,           sparse(m, m*n)  ,            sparse(m, m)       ,   sparse(m, n)      ,     sparse(m, m*q)  ,          kron(speye(m), a),                sparse(m, q)  ,                sparse(m, w)               sparse(m, m*p)  ,           sparse(m, m)  ,                -speye(m, m)  ];


% Define Optimise Cardinality problem:
% Define p, vector for zero-norm cardinality
variableSize = (m*n) + (m*n) + m + n + (m*q) + (m*w) + (q*1) + (w*1) + (m*p) + (m*1) + (m*1);
problem.p = false(variableSize, 1);
% ||vec(X)||_0
problem.p(1:(m*n)) = true;

% ||vec(U)||_0
problem.p((m*n) + (m*n) + m + n +1:(m*n) + (m*n) + m + n + (m*q)) = true;

% ||vec(H)||_0
problem.p((m*n) + (m*n) + m + n + (m*q) + 1:(m*n) + (m*n) + m + n + (m*q) + (m*w)) = true;

% Define q vector for one-norm cardinality
problem.q = false(variableSize, 1);

% ||(y)||_1
problem.q(2*m*n+1: 2*m*n+m+1) = true;

% ||beta||_1 + ||gamma||_1
problem.p((m*n) + (m*n) + m + n + (m*q) + (m*w) + (q*1) + (w*1) + (m*p) + 1 : end) = true;

% Define rho coefficient to scale total cost objectives. rho = 0.01
problem.o = ones(variableSize, 1);
problem.o((m*n) + (m*n) + m + n + (m*q) + (m*w) + (q*1) + (w*1) + (m*p) + 1 : end) = 0.01;

% Define r
problem.r = ~(problem.p + problem.q);

% Define bounds
lb = zeros(variableSize, 1);
% Relax the upper bound
ub = 10000 + zeros(variableSize, 1);

% set the lower bounds for X variable
lb(1:(m*n)) = 0;
ub(1:(m*n)) = 1;

% Set number of patients per IMD to the half possible value y
% if       lb_y <  y  <  ub_y
% Then    -lb_y > -y  > -ub_y
% Assume minimum 15 patients per IMD
% Set number of patients to numbers calculated by Diagnostic Confidence Score
lb(m*n+m*n+1: m*n+m*n+m) = ceil(0.5 * patientNumberLB);

ub(m*n+m*n+1: m*n+m*n+m) = patientNumberUB;


% Minimum 50 patients to be recruited at each hospital
ub(m*n+m*n+m+1: m*n+m*n+m+n) = HCPpatientNumberUB;

% Define csense
csense = [repmat('E', m*n+m+n, 1); repmat('G', 2*m*p, 1); repmat('E', q + w + m*p + 2*m, 1)];
problem.p = logical(problem.p);
problem.q = logical(problem.q);
problem.r = logical(problem.r);
problem.A = LHS;
problem.b = zeros(size(problem.A, 1), 1);
problem.ub = ub;
problem.lb = lb;
problem.c = zeros(size(problem.A,2),1);
problem.csense = csense;
param.printLevel=1;

targeted_caps = 0:200:2000;
global_caps = 0:200:2000;

feas_map_heur = zeros(numel(global_caps), numel(targeted_caps));
feas_map_greedy = zeros(numel(global_caps), numel(targeted_caps));
feasibility_map = zeros(numel(global_caps), numel(targeted_caps));  % values 0..7

for i = 1:numel(global_caps) %[output:group:19c4cc3b]
    for j = 1:numel(targeted_caps)
        gc = global_caps(i);
        tc = targeted_caps(j);
        opt_feasible = true;
        heur_feasible = true;

        % Set a cap on samples per site u
        problem.ub((m*n) + (m*n) + m + n + (m*q) + (m*w) + 1: (m*n) + (m*n) + m + n + (m*q) + (m*w) + q) = repmat(tc, q, 1);

        % Set a cap on samples per site h
        problem.ub((m*n) + (m*n) + m + n + (m*q) + (m*w) + (q*1) + 1: (m*n) + (m*n) + m + n + (m*q) + (m*w) + (q*1) + (w*1)) = repmat(gc, w, 1);

        try
            solution = optimizeCardinality(problem, param); %[output:3b6c771a]
            % U
            U_opt = solution.xyz(2*m*n+m+n+1: 2*m*n+m+n+m*q);
            U_opt = reshape(U_opt, q, m);

            % H
            H_opt = solution.xyz(2*m*n+m+n+m*q+1: 2*m*n+m+n+m*q+m*w);
            H_opt = reshape(H_opt, w, m);
            targSamples_opt = sum(U_opt, 2);   % q×1
            globSamples_opt = sum(H_opt, 2);   % w×1
            costT_opt = sum(targSamples_opt .* r(:));
            costG_opt = sum(globSamples_opt .* a(:));
            totalCost_opt = costT_opt + costG_opt;

        catch
            opt_feasible = false;
        end

        try
            [U_heur, H_heur, costT_heur, costG_heur, totalCost_heur] = HeuristicSampleAllocation(y, T, G, r, a, B, repmat(tc, q, 1), repmat(gc, w, 1));
        catch
            heur_feasible = false;
        end

        greedy_feasible = true;

        % --- Greedy baseline ---
        try
            optsGreedy = struct();
            optsGreedy.batchMode = false;
            optsGreedy.activationPenaltyT = 0;
            optsGreedy.activationPenaltyG = 0;
            optsGreedy.useTwoXCoverage = true;
            optsGreedy.nRestarts = 20;        % try 20 independent runs
            optsGreedy.rngSeed   = 1;         % reproducible
            optsGreedy.pickBestBy = 'totalCost';  % keep best feasible solution

            [U_g, H_g] = GlobalGreedyMarginalSampleAllocation( ...
                y, T, G, r, a, B, repmat(tc, q, 1), repmat(gc, w, 1));
        catch
            greedy_feasible = false;
        end

        % Unified 3-method feasibility code (0..7)
        % bit0 (1): optimisation feasible
        % bit1 (2): heuristic feasible
        % bit2 (4): greedy feasible
        feasibility_map(i,j) = 1*opt_feasible + 2*heur_feasible + 4*greedy_feasible;

    end
end %[output:group:19c4cc3b]

% Check to make sure all the results are digits
assert( all(Y_opt(:) == round(Y_opt(:))), 'Matrix Y must contain only integer values.');
assert( all(H_opt(:) == round(H_opt(:))), 'Matrix H must contain only integer values.');
assert( all(U_opt(:) == round(U_opt(:))), 'Matrix U must contain only integer values.');
%% ===== Simplified 3-Scenario Feasibility Map =====

% 1. Data Preparation
present = unique(feasibility_map(:));
present = sort(present(:))';

% Define colors ONLY for 0, 1, 7
colorMapFull = containers.Map('KeyType','double','ValueType','any');
colorMapFull(0) = [255, 179, 186]/255;   % Red
colorMapFull(1) = [255, 250, 139]/255;   % Yellow
colorMapFull(7) = [119, 221, 119]/255;   % Green

cmap = zeros(numel(present),3);
for k = 1:numel(present)
    cmap(k,:) = colorMapFull(present(k));
end

map_reindexed = zeros(size(feasibility_map));
for k = 1:numel(present)
    map_reindexed(feasibility_map == present(k)) = k;
end

% 2. Figure Creation 
% Increased width to 11 inches to accommodate larger font sizes on the right
fig = figure('Units','inches','Position',[1,1,11,6], 'Color', 'w'); %[output:229e8e90]
tlo = tiledlayout(1,1,'Padding','loose','TileSpacing','compact'); %[output:229e8e90]
ax = nexttile(tlo); %[output:229e8e90]

% 3. Plotting
imagesc(targeted_caps, global_caps, map_reindexed); %[output:229e8e90]
colormap(ax, cmap); %[output:229e8e90]
set(ax, 'CLim', [0.5, numel(present)+0.5]); %[output:229e8e90]
set(ax, 'YDir', 'normal'); %[output:229e8e90]

% SET AXIS TICK FONT SIZE
set(ax, 'FontName', 'Arial', 'FontSize', 16);  %[output:229e8e90]

xticks(0:400:max(targeted_caps)); %[output:229e8e90]
yticks(0:400:max(global_caps)); %[output:229e8e90]

% SET LABELS AND TITLE FONT SIZE
xlabel('Targeted Platform Capacity', 'FontSize', 16); %[output:229e8e90]
ylabel('Global Platform Capacity', 'FontSize', 16); %[output:229e8e90]
% title('Feasibility Comparison of Allocation Strategies', ...
%       'FontWeight','normal', 'FontSize', 18);

% 4. Colorbar Configuration
labelMap = containers.Map('KeyType','double','ValueType','char');
labelMap(0) = 'None feasible';
labelMap(1) = 'Only Optimised feasible';
labelMap(7) = 'All methods feasible';

labels = cell(1,numel(present));
for k = 1:numel(present)
    labels{k} = labelMap(present(k));
end

cb = colorbar(ax); %[output:229e8e90]
cb.Layout.Tile = 'east';  %[output:229e8e90]
cb.Ticks = 1:numel(present); %[output:229e8e90]
cb.TickLabels = labels; %[output:229e8e90]

% INCREASE COLORBAR FONT SIZE
cb.FontSize = 16;  %[output:229e8e90]
cb.TickLabelInterpreter = 'none';  %[output:229e8e90]

% 5. Export
if ~exist(graphicFolder, 'dir'), mkdir(graphicFolder); end

exportgraphics(fig, fullfile(graphicFolder, 'feasibility_comparison.png'), ... %[output:group:1df14f4f] %[output:229e8e90]
    'Resolution', 600, ... %[output:229e8e90]
    'BackgroundColor', 'white'); %[output:group:1df14f4f] %[output:229e8e90]

